#include "general.h"
#include <stdio.h>
#include <string.h>
#include <math.h>

/* ── I2C handles (generated by CubeMX) ─────────────────────────
   hi2c1 : PB6/PB7  → MPU6050 + HMC5883L
   hi2c2 : PB10/PB11 → SSD1306 OLED                             */
extern I2C_HandleTypeDef hi2c1;
extern I2C_HandleTypeDef hi2c2;

/* ── Global map (declared here, extern'd in general.h) ─────────*/
Map g_map;

/* ── Module-private state ───────────────────────────────────────*/
static uint8_t  s_oled_page    = OLED_PAGE_MAP;
static uint32_t s_last_oled_ms = 0;
static uint32_t s_last_imu_ms  = 0;
static uint32_t s_last_us_ms   = 0;
static uint8_t  s_us_index     = 0;    /* which sensor to trigger next */

/* CORRECTED: MPU6050_RawData instead of MPU6500 */
static MPU6050_RawData  s_imu_raw  = {0};
static HMC5883L_RawData s_mag_raw  = {0};
static Orientation      s_orient   = {0};
static RobotPose        s_pose     = {0};

/* Sensor status flags set during Init */
static uint8_t s_mpu_ok = 0;
static uint8_t s_hmc_ok = 0;

/* ═══════════════════════════════════════════════════════════════ */
/* OLED MAP PAGE renderer                                         */
/* Draws 8 × 4 = 32 blocks of 16 × 16 pixels.                    */
/* ┌──────────────────────────────────────────────────────────┐   */
/* │  UNKNOWN  = white outline only                           │   */
/* │  CLEAN    = white fill                                   │   */
/* │  OBSTACLE = white fill + 10×10 black centre             │   */
/* │  ROBOT    = 4×4 black square at cell centre             │   */
/* └──────────────────────────────────────────────────────────┘   */
/* ═══════════════════════════════════════════════════════════════ */
static void render_map_page(void)
{
    int vx0, vy0;
    Map_GetViewport(&g_map, &vx0, &vy0);

    int robot_cx = Map_RobotCellX(&g_map);
    int robot_cy = Map_RobotCellY(&g_map);

    OLED_Clear();

    for (int row = 0; row < VIEW_ROWS; row++) {
        for (int col = 0; col < VIEW_COLS; col++) {

            int   grid_x = vx0 + col;
            int   grid_y = vy0 + row;
            uint8_t cell = Map_GetCell(&g_map, grid_x, grid_y);

            uint16_t px = (uint16_t)(col * BLOCK_PX);
            uint16_t py = (uint16_t)(row * BLOCK_PX);

            switch (cell) {

                case CELL_UNKNOWN:
                    /* White border, 1 px thick */
                    OLED_DrawOutline(px, py, BLOCK_PX, BLOCK_PX);
                    break;

                case CELL_FREE:
                    /* Fully white (cleaned) */
                    OLED_Rectangle(px, py, BLOCK_PX, BLOCK_PX);
                    break;

                case CELL_OCCUPIED:
                    /* White block with 10×10 black obstacle mark */
                    OLED_Rectangle(px, py, BLOCK_PX, BLOCK_PX);
                    OLED_ClearArea(px + OBSTACLE_OFF, py + OBSTACLE_OFF, OBSTACLE_PX, OBSTACLE_PX);
                    break;

                default: break;
            }

            /* ── Robot marker ────────────────────────────────── */
            if (grid_x == robot_cx && grid_y == robot_cy) {
                /* 4×4 black square at block centre on cleaned cell,
                   4×4 white square on unknown cell */
                if (cell == CELL_UNKNOWN) {
                    OLED_Rectangle(px + 6, py + 6, 4, 4);
                } else {
                    OLED_ClearArea(px + 6, py + 6, 4, 4);
                }
            }
        }
    }

    OLED_Update();
}

/* ═══════════════════════════════════════════════════════════════ */
/*  PAGE 1 — ULTRASONIC                                            */
/*                                                                  */
/*  FIX: last_dist[] caches the most recent valid reading per      */
/*  sensor. miss_count[] only shows NO ECHO after 4 consecutive    */
/*  missed echoes — prevents flashing caused by the brief window   */
/*  between Trigger() and CaptureCallback() firing.                */
/* ═══════════════════════════════════════════════════════════════ */

#define NO_ECHO_THRESHOLD  4   /* consecutive misses before showing NO ECHO */

static void render_ultrasonic_page(void)
{
    char line[32];

    static float   last_dist[4]  = {-1.f, -1.f, -1.f, -1.f};
    static uint8_t miss_count[4] = {0, 0, 0, 0};

    const char    *labels[4] = {"F", "R", "B", "L"};
    const uint8_t  y_pos[4]  = {14, 24, 34, 44};

    OLED_Clear();
    OLED_Print(0, 0, "-- Ultrasonic --");

    for (int i = 0; i < 4; i++) {

        if (ultrasonic[i].status == US_OK && ultrasonic[i].ready) {
            /* New valid reading — update cache, reset miss counter */
            last_dist[i]  = ultrasonic[i].distance_m;
            miss_count[i] = 0;
        } else if (ultrasonic[i].status == US_NO_ECHO) {
            /* Genuine timeout set by CheckTimeout() — count it   */
            if (miss_count[i] < 255) miss_count[i]++;
        }
        /* If status==US_OK but ready==0: trigger just fired,
           echo not received yet — don't change miss_count         */

        if (miss_count[i] >= NO_ECHO_THRESHOLD || last_dist[i] < 0.0f) {
            snprintf(line, sizeof(line), "%s: NO ECHO", labels[i]);
        } else {
            snprintf(line, sizeof(line), "%s:%5.2fm %5luus",
                     labels[i],
                     (double)last_dist[i],
                     (unsigned long)ultrasonic[i].pulse_us);
        }
        OLED_Print(0, y_pos[i], line);
    }

    /* Bottom row: IMU sensor status                               */
    snprintf(line, sizeof(line), "MPU:%s HMC:%s",
             s_mpu_ok ? "OK" : "ERR",
             s_hmc_ok ? "OK" : "ERR");
    OLED_Print(0, 54, line);

    OLED_Update();
}

/* ═══════════════════════════════════════════════════════════════ */
/* OLED IMU PAGE                                                  */
/* ═══════════════════════════════════════════════════════════════ */
static void render_imu_page(void)
{
    char buf[22];
    OLED_Clear();

    OLED_Print(0, 0, "---- IMU ----");

    /* Gyro rates in deg/s */
    float gx = s_imu_raw.gx / 131.0f;
    float gy = s_imu_raw.gy / 131.0f;
    float gz = s_imu_raw.gz / 131.0f;

    snprintf(buf, sizeof(buf), "Gx%+6.1f Gy%+6.1f", (double)gx, (double)gy);
    OLED_Print(0, 14, buf);

    snprintf(buf, sizeof(buf), "Gz%+6.1f d/s", (double)gz);
    OLED_Print(0, 28, buf);

    /* Roll / Pitch / Yaw */
    snprintf(buf, sizeof(buf), "R%+6.1f P%+6.1f",
             (double)s_orient.roll, (double)s_orient.pitch);
    OLED_Print(0, 42, buf);

    snprintf(buf, sizeof(buf), "Yaw: %6.1f deg", (double)s_orient.yaw);
    OLED_Print(0, 54, buf);

    OLED_Update();
}

/* ═══════════════════════════════════════════════════════════════ */
/* OLED POSITION PAGE                                             */
/* ═══════════════════════════════════════════════════════════════ */
static void render_position_page(void)
{
    char buf[22];
    OLED_Clear();

    OLED_Print(0, 0, "-- Position --");

    snprintf(buf, sizeof(buf), "X: %7.3f m", (double)s_pose.x);
    OLED_Print(0, 14, buf);

    snprintf(buf, sizeof(buf), "Y: %7.3f m", (double)s_pose.y);
    OLED_Print(0, 28, buf);

    snprintf(buf, sizeof(buf), "H: %6.1f deg", (double)s_pose.theta);
    OLED_Print(0, 42, buf);

    snprintf(buf, sizeof(buf), "Spd:%4.2fm/s Cl:%lu",
             (double)ODOM_GetSpeed(),
             (unsigned long)g_map.cells_cleaned);
    OLED_Print(0, 54, buf);

    OLED_Update();
}

/* ═══════════════════════════════════════════════════════════════ */
/* GENERAL_Init                                                   */
/* ═══════════════════════════════════════════════════════════════ */
void GENERAL_Init(void)
{
    /* ── OLED ────────────────────────────────────────────────── */
    OLED_Init(&hi2c2);
    OLED_Clear();

    /* Using your OLED wrapper to print splash screen text */
    OLED_Print(16, 20, "Floor Robot");
    OLED_Print(20, 44, "Initialising...");
    OLED_Update();

    /* ── MPU6050 ─────────────────────────────────────────────── */
    if (MPU6050_Check(&hi2c1) == MPU_OK) {
        MPU6050_Init();   /* includes CalibrateGyro (~1 s) */
        s_mpu_ok = 1;
    }

    /* ── HMC5883L ────────────────────────────────────────────── */
    if (HMC5883L_Check(&hi2c1) == HMC_OK) {
        HMC5883L_Init();
        s_hmc_ok = 1;
    }

    /* ── Ultrasonic ──────────────────────────────────────────── */
    ULTRASONIC_Init();

    /* ── Buttons ─────────────────────────────────────────────── */
    BTNS_Init();

    /* ── Orientation filter ──────────────────────────────────── */
    STABLE_Init();

    /* ── Odometry + Map ─────────────────────────────────────── */
    ODOM_Init();
    Map_Init(&g_map);

    /* Splash hold */
    HAL_Delay(500);
    OLED_Clear();
    OLED_Update();
}

/* ═══════════════════════════════════════════════════════════════ */
/* GENERAL_Update — call from main() while(1) loop               */
/* ═══════════════════════════════════════════════════════════════ */
void GENERAL_Update(void)
{
    uint32_t now = HAL_GetTick();

    /* ── Buttons ─────────────────────────────────────────────── */
    BTNS_Update();
    if (BTNS_Get_OLEDPage() == BTN_PRESSED) {
        s_oled_page = (s_oled_page + 1) % OLED_NUM_PAGES;
    }

    /* ── IMU + Orientation (10 ms period = 100 Hz) ───────────── */
    if ((now - s_last_imu_ms) >= IMU_UPDATE_INTERVAL_MS) {
        float dt = (float)(now - s_last_imu_ms) * 0.001f;
        s_last_imu_ms = now;

        /* CORRECTED: Changed MPU6500_ReadRaw to MPU6050_ReadRaw */
        if (s_mpu_ok) MPU6050_ReadRaw(&s_imu_raw);
        if (s_hmc_ok) HMC5883L_ReadRaw(&s_mag_raw);

        STABLE_Update(&s_imu_raw, &s_mag_raw, dt);
        s_orient = STABLE_GetOrientation();

        /* Update position from IMU (motors off — manual push)    */
        ODOM_UpdateIMU(&s_imu_raw, s_orient.yaw, dt);
        s_pose = ODOM_GetPose();

        /* Mark current cell as cleaned                           */
        Map_UpdateRobotPose(&g_map,
                             s_pose.x, s_pose.y, s_pose.theta);
    }

    /* ── Ultrasonic round-robin (25 ms per sensor) ───────────── */
    if ((now - s_last_us_ms) >= US_TRIGGER_INTERVAL_MS) {
        s_last_us_ms = now;
        ULTRASONIC_CheckTimeout();

        /* Read the sensor that was triggered last period          */
        uint8_t read_idx = (s_us_index + 3) % 4;   /* previous index */
        float dist = ULTRASONIC_GetDistance(read_idx);

        static const float sensor_angles[4] = {
            US_ANGLE_0, US_ANGLE_1, US_ANGLE_2, US_ANGLE_3
        };

        if (dist > 0.05f) {   /* > 5 cm = plausible reading       */
            Map_UpdateUltrasonic(&g_map, dist, sensor_angles[read_idx]);
        }

        /* Trigger the next sensor                                 */
        ULTRASONIC_Trigger(s_us_index);
        s_us_index = (s_us_index + 1) % 4;
    }

    /* ── OLED refresh (200 ms = 5 Hz) ───────────────────────── */
    if ((now - s_last_oled_ms) >= OLED_UPDATE_INTERVAL_MS) {
        s_last_oled_ms = now;

#if ENABLE_OLED_DEBUG
        GENERAL_OLED_Debug();
#endif
    }
}

/* ─────────────────────────────────────────────────────────────── */
void GENERAL_ResetPose(void)
{
    ODOM_SetPose(15.0f, 15.0f, 0.0f);
    ODOM_ResetVelocity();
    s_pose = ODOM_GetPose();
}

/* ─────────────────────────────────────────────────────────────── */
#if ENABLE_OLED_DEBUG
void GENERAL_OLED_Debug(void)
{
    switch (s_oled_page) {
        case OLED_PAGE_MAP:        render_map_page();        break;
        case OLED_PAGE_ULTRASONIC: render_ultrasonic_page(); break;
        case OLED_PAGE_IMU:        render_imu_page();        break;
        case OLED_PAGE_POSITION:   render_position_page();   break;
        default:                   render_map_page();        break;
    }
}
#endif

/* ─────────────────────────────────────────────────────────────── */
#if ENABLE_OLED_SELFTEST
void GENERAL_OLED_SelfTest(void)
{
    /* Draw all block types across the screen */
    OLED_Clear();

    /* Row 0: unknown blocks (outlines) */
    for (int c = 0; c < VIEW_COLS; c++) {
        OLED_DrawOutline(c * 16, 0, 16, 16);
    }
    /* Row 1: clean blocks */
    for (int c = 0; c < VIEW_COLS; c++) {
        OLED_Rectangle(c * 16, 16, 16, 16);
    }
    /* Row 2: obstacle blocks */
    for (int c = 0; c < VIEW_COLS; c++) {
        OLED_Rectangle(c * 16, 32, 16, 16);
        OLED_ClearArea(c * 16 + 3, 35, 10, 10);
    }
    /* Row 3: robot marker */
    for (int c = 0; c < VIEW_COLS; c++) {
        OLED_DrawOutline(c * 16, 48, 16, 16);
    }
    /* Robot at cell (2, 3) */
    OLED_Rectangle(2 * 16 + 6, 48 + 6, 4, 4);

    OLED_Update();
}
#endif
